#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_inlet_open = controller->inlet_open;
    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    /* Handle sensor timeout/invalid input - go to safe all-off */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* No input - stay in safe idle */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Update sensor state */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    default:
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Check if either sensor is stale - go to safe all-off */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Apply the fill-and-heat control policy */
    bool level_low = controller->last_level < CONTROLLER_FILL_LEVEL_THRESHOLD;  // level < 60
    bool level_high = controller->last_level > CONTROLLER_LEVEL_HIGH_THRESHOLD;  // level > 75
    bool level_safe = controller->last_level >= CONTROLLER_FILL_LEVEL_THRESHOLD && 
                      controller->last_level <= CONTROLLER_LEVEL_HIGH_THRESHOLD;  // 60-75
    bool temp_low = controller->last_temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD;  // temp < 45
    bool temp_early_off_range = controller->last_temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
                                 controller->last_temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD;  // 47-48
    bool temp_high = controller->last_temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD;  // temp > 48

    /* Rule: If LEVEL < 55, keep HEATER OFF even when temperature is low */
    bool heater_off_due_to_low_level = controller->last_level < CONTROLLER_MIN_HEATING_LEVEL;  // level < 55

    /* Determine inlet and heater state based on policy */
    bool new_inlet_open = false;
    bool new_heater_on = false;

    if (level_low) {
        /* FILLING: level < 60, keep inlet open, heater off */
        new_inlet_open = true;
        new_heater_on = false;
    } else if (level_high) {
        /* Level too high - close inlet */
        new_inlet_open = false;
        if (!heater_off_due_to_low_level && temp_low) {
            /* If level is safe and temp is low, turn on heater */
            new_heater_on = true;
        } else {
            new_heater_on = false;
        }
    } else if (level_safe) {
        /* Level is in safe band 60-75 */
        if (!temp_low && temp_early_off_range) {
            /* Check if temperature is rising - if so, turn heater off early */
            bool temp_rising = controller->last_temperature_c > controller->previous_temperature_c;
            if (temp_rising) {
                new_inlet_open = false;
                new_heater_on = false;  /* Turn off heater early */
            } else {
                new_inlet_open = false;
                new_heater_on = true;  /* Hold previous safe state - heater on */
            }
        } else if (!temp_low) {
            /* Temp >= 45, level is safe - heat */
            new_inlet_open = false;
            new_heater_on = true;
        } else {
            /* Temp < 45, level is safe - close inlet but don't heat yet */
            new_inlet_open = false;
            new_heater_on = false;
        }
    } else {
        /* Level outside safe band (< 60 or > 75) */
        if (level_low) {
            /* FILLING - already handled above */
            new_inlet_open = true;
            new_heater_on = false;
        } else {
            /* Level > 75, too high - close inlet and heater */
            new_inlet_open = false;
            new_heater_on = false;
        }
    }

    /* Apply the new state */
    controller->inlet_open = new_inlet_open;
    controller->heater_on = new_heater_on;

    /* Determine state based on current configuration */
    if (new_inlet_open) {
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (new_heater_on && !level_low) {
        /* Heater is on but not in filling state - could be heating or holding */
        if (temp_early_off_range) {
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            controller->state = CONTROLLER_STATE_HEATING;
        }
    } else {
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
    }

    output.inlet_open = new_inlet_open;
    output.heater_on = new_heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != new_inlet_open) ||
        (previous_heater_on != new_heater_on) ||
        (previous_state != controller->state);

    return output;
}

